14: ## Phase 1: Robust Web Storage & Quota Management
15: 
16: ### Rationale:
17: On Web, unawaited `prefs.setString` calls throw `QuotaExceededError` DOMExceptions asynchronously outside of standard `try-catch` blocks, causing browser/app crashes when `localStorage` is full.
18: 
19: ### Target: `lib/services/async_store.dart`
20: 
21: ```dart
22: // 1. Declare class-level static boolean flag
23: static bool _isQuotaExceeded = false;
24: 
25: // 2. Update the update method:
26: static Future<void> update(String key, dynamic val) async {
27:   if (!kIsWeb) {
28:     final parts = key.split(':');
29:     if (parts.length >= 2) {
30:       await SqliteHelper.update(parts[0], parts.sublist(1).join(':'), val);
31:       return;
32:     }
33:   }
34: 
35:   final jsonStr = jsonEncode(val);
36:   if (kIsWeb) _webCache[key] = jsonStr;
37: 
38:   if (kIsWeb && _isQuotaExceeded) {
39:     return; // Short-circuit persistent storage writes once quota is exceeded
40:   }
41: 
42:   final prefs = await _getPrefs();
43:   try {
44:     await prefs.setString(key, jsonStr);
45:   } catch (e) {
46:     if (e.toString().contains("QuotaExceededError") ||
47:         e.toString().contains("quota") ||
48:         e.toString().contains("NS_ERROR_DOM_QUOTA_REACHED")) {
49:       _isQuotaExceeded = true;
50:       debugPrint("AsyncStore: Quota Exceeded. Kept in-memory.");
51:     } else {
52:       rethrow;
53:     }
54:   }
55: }
56: 
57: // 3. Update the updateAll method:
58: static Future<void> updateAll(String dbName, Map<String, dynamic> items) async {
59:   if (!kIsWeb) {
60:     await SqliteHelper.updateAll(dbName, items);
61:     return;
62:   }
63: 
64:   final prefs = await _getPrefs();
65:   
66:   for (var entry in items.entries) {
67:     final jsonStr = jsonEncode(entry.value);
68:     if (kIsWeb) _webCache[entry.key] = jsonStr;
69:     
70:     if (_isQuotaExceeded) continue;
71: 
72:     try {
73:       await prefs.setString(entry.key, jsonStr);
74:     } catch (e) {
75:       if (e.toString().contains("QuotaExceededError") ||
76:           e.toString().contains("quota") ||
77:           e.toString().contains("NS_ERROR_DOM_QUOTA_REACHED")) {
78:         _isQuotaExceeded = true;
79:         debugPrint("AsyncStore.updateAll: Web Quota Exceeded. Kept in-memory.");
80:       } else {
81:         rethrow;
82:       }
83:     }
84:   }
85: }
86: 
87: // 4. Update clear & clearAll methods to reset the flag:
88: static Future<void> clear(String dbName) async {
89:   ...
90:   _isQuotaExceeded = false; // Reset quota exceeded status
91: }
92: 
93: static Future<void> clearAll() async {
94:   ...
95:   _isQuotaExceeded = false; // Reset quota exceeded status
96: }
97: ```
