      stmt.execute([id, businessKeyVal, isActive, jsonEncode(entry.value)]);

      final int ts = _getLatestDateStatic(recordVal);
      stmtTs.execute([dbName, id, isActive, ts]);
    }
    stmt.dispose();
    stmtTs.dispose();
    db.execute('COMMIT');
  } catch (e) {
    db.execute('ROLLBACK');
    rethrow;
  }

