        } catch (_) {}
        stmt.execute([dbName, id, isActive, ts]);
      }
      stmt.dispose();
      db.execute('COMMIT');
    } catch (e) {
      db.execute('ROLLBACK');
      debugPrint("SqliteHelper: Backfill failed: $e");
    }
  }
}

